CREATE INDEX IF NOT EXISTS idx_audit_entity
    ON audit_log (entity_type, entity_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_audit_actor
    ON audit_log (actor_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_audit_status_changes
    ON audit_log (entity_type, entity_id, action)
    WHERE action = 'STATUS_CHANGED';
CREATE INDEX IF NOT EXISTS idx_audit_changes_gin
    ON audit_log USING GIN (changes);

rollback.sql:
DROP INDEX IF EXISTS idx_audit_entity;
DROP INDEX IF EXISTS idx_audit_actor;
DROP INDEX IF EXISTS idx_audit_status_changes;
DROP INDEX IF EXISTS idx_audit_changes_gin;

changeSet.sql:
    CREATE OR REPLACE FUNCTION update_personal_fts_name()
RETURNS TRIGGER AS $BODY$
    BEGIN
    NEW.fts_name := to_tsvector('russian',
        coalesce(NEW.last_name,   '') || ' ' ||
        coalesce(NEW.first_name,  '') || ' ' ||
        coalesce(NEW.middle_name, '') || ' ' ||
        coalesce(NEW.phone,       '')
    );
    RETURN NEW;
    END;
    $BODY$ LANGUAGE plpgsql;

CREATE TRIGGER trg_personal_data_fts
    BEFORE INSERT OR UPDATE ON customer_personal_data
                         FOR EACH ROW EXECUTE FUNCTION update_personal_fts_name();

    CREATE OR REPLACE FUNCTION update_org_fts_name()
RETURNS TRIGGER AS $BODY$
    BEGIN
    NEW.fts_name := to_tsvector('russian',
        coalesce(NEW.org_name, '') || ' ' ||
        coalesce(NEW.inn,      '')
    );
    RETURN NEW;
    END;
    $BODY$ LANGUAGE plpgsql;

CREATE TRIGGER trg_org_data_fts
    BEFORE INSERT OR UPDATE ON customer_org_data
                         FOR EACH ROW EXECUTE FUNCTION update_org_fts_name();

rollback.sql:
DROP TRIGGER IF EXISTS trg_personal_data_fts ON customer_personal_data;
DROP TRIGGER IF EXISTS trg_org_data_fts ON customer_org_data;
DROP FUNCTION IF EXISTS update_personal_fts_name();
DROP FUNCTION IF EXISTS update_org_fts_name();

DELETE FROM customer_org_data
WHERE customer_id IN (SELECT id FROM customers WHERE id LIKE 'c0000000%');
DELETE FROM customer_personal_data
WHERE customer_id IN (SELECT id FROM customers WHERE id LIKE 'c0000000%');

